const ToolsSection = () => {
  const [isPaused, setIsPaused] = useState(false);
  const marqueeRef = useRef<HTMLDivElement>(null);

  const duplicatedTools = [...tools, ...tools, ...tools, ...tools];

  return (
    <section className="relative py-24 overflow-hidden">
      {/* Section title */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        whileInView={{ opacity: 1, y: 0 }}
        viewport={{ once: true }}
        transition={{ duration: 0.6 }}
        className="text-center mb-16"
      >
        <p className="text-neon-purple font-mono text-sm tracking-[0.25em] uppercase mb-3">
          My Stack
        </p>
        <h2 className="font-display text-4xl sm:text-5xl font-bold gradient-text">
          Tools I Use
        </h2>
      </motion.div>

      {/* Marquee container */}
      <div
        className="relative"
        onMouseEnter={() => setIsPaused(true)}
        onMouseLeave={() => setIsPaused(false)}
      >
        {/* Fade edges */}
        <div className="absolute left-0 top-0 bottom-0 w-24 sm:w-40 bg-gradient-to-r from-background to-transparent z-10 pointer-events-none" />
        <div className="absolute right-0 top-0 bottom-0 w-24 sm:w-40 bg-gradient-to-l from-background to-transparent z-10 pointer-events-none" />

        {/* Scrolling strip */}
        <div className="overflow-hidden">
          <div
            ref={marqueeRef}
            className="flex will-change-transform"
            style={{
              animation: `tools-marquee 40s linear infinite`,
              animationPlayState: isPaused ? "paused" : "running",
            }}
          >
            {duplicatedTools.map((tool, i) => (
              <div
                key={`${tool.name}-${i}`}
                className="flex-shrink-0 px-6 sm:px-10"
              >
                <div className="group flex flex-col items-center gap-3 cursor-default">
                  <div
                    className="relative w-16 h-16 sm:w-20 sm:h-20 rounded-2xl glass flex items-center justify-center transition-all duration-300 group-hover:scale-110 group-hover:border-neon-purple/40"
                    style={{
                      transition: "all 0.3s cubic-bezier(0.4, 0, 0.2, 1)",
                    }}
                  >
                    <div
                      className="text-muted-foreground/50 transition-all duration-300 group-hover:text-foreground group-hover:drop-shadow-[0_0_12px_var(--glow)]"
                      style={
                        {
                          "--glow": `${tool.color}80`,
                        } as React.CSSProperties
                      }
                    >
                      {tool.svg}
                    </div>
                    {/* Glow ring on hover */}
                    <div
                      className="absolute inset-0 rounded-2xl opacity-0 group-hover:opacity-100 transition-opacity duration-300 pointer-events-none"
                      style={{
                        boxShadow: `0 0 24px ${tool.color}20, inset 0 0 24px ${tool.color}08`,
                      }}
                    />
                  </div>
                  <span className="text-xs sm:text-sm text-muted-foreground/60 font-medium tracking-wide group-hover:text-foreground transition-colors duration-300">
                    {tool.name}
                  </span>
                </div>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Keyframes injected via style tag */}
      <style>{`
        @keyframes tools-marquee {
          0% { transform: translateX(0); }
          100% { transform: translateX(-50%); }
        }
      `}</style>
    </section>
  );
};

export default ToolsSection;
